"""
MKT Original Language Commentary — Esther chapters 6–10
Run: python3 scripts/zc-original-esther-6-10-full.py

Ch 6: Sleepless king's chronicles reading → Mordecai's unrewarded deed found → Haman
  enters for the execution request just as the king asks how to honor Mordecai →
  Haman proposes the honor for himself but must give it to Mordecai.
Ch 7: Esther's second banquet → she reveals the plot against her people → Haman falls
  on her couch → Haman is hanged on the gallows he prepared for Mordecai.
Ch 8: Esther intercedes for reversal of Haman's decree → Mordecai elevated → new
  decree allowing the Jews to assemble and defend themselves.
Ch 9: The battle on Adar 13-14 → Jews prevail throughout the empire → Haman's 10 sons
  killed → additional day in Susa → establishment of Purim as annual feast.
Ch 10: Mordecai's greatness summary — second to the king, advocate for his people.

Key linguistic observations:
- ʿad-ḥăṣî hammalkûṯ ('up to half the kingdom') — the Persian royal formula of unlimited
  generosity (6:6; 7:2) vs. the covenantal boundary that cannot be purchased
- šlōmô ('his peace/welfare') — Mordecai's concern for his people (10:3) echoes Gen 43:27
- pûr ('lot') — the Akkadian loanword governing the book's title and the feast's meaning
- ʾôyēḇ wəṣārēr ('enemy and adversary') — the paired accusation formula (7:6)
- nāḥat mēʾôyəḇêhem ('rest from their enemies') — the Deuteronomic rest formula (9:16,22)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EST_ORIGINAL_6_10 = {
  "6": {
    "1": "<p><strong>ballaylāh hahûʾ nāḏəḏāh šənaṯ hammeleḵ</strong> — 'On that night the sleep of the king fled' (<em>nāḏaḏ</em>, H5074 = to flee, stray; used elsewhere for fugitives and scattered birds). The subject is the abstract noun <em>šənāt</em> (sleep, H8142) — in the idiom of biblical narrative the sleep itself becomes the subject that flees, as if animated. The rabbis read this as the sleep of God himself (Midrash Esther Rabbah): 'the Sleep of the King of the Universe fled.' Without naming divine agency, the narrator uses the passive description of a king's insomnia at precisely the critical moment — the night before Haman plans to request Mordecai's execution — to signal providential timing. <strong>wayyōʾmer lhāḇîʾ ʾeṯ-sēfer hazziḵrōnôṯ diḇrê hayyāmîm</strong> — 'and he commanded that the book of records of the chronicles (<em>sēfer hazziḵrōnôṯ diḇrê hayyāmîm</em>) be brought.' The term <em>zikkārôn</em> (H2146 = memorial, record, that which calls to mind) designates the court chronicles that preserve the memory of significant acts. The same root as Mordecai's unrecorded (until now) act of loyalty.</p>",
    "2": "<p><strong>wayyimmāṣēʾ kāṯûḇ</strong> — 'and it was found written' (<em>māṣāʾ</em>, H4672, niphal = to be found; the passive emphasizes that no human directed the search to this particular entry). The passive construction is characteristic of Esther's narrative theology: things are 'found,' appointments 'happen,' the king 'could not sleep' — agency is never attributed to human calculation or divine intervention but to a series of passive events that accumulate. What is found written is the specific account of Mordecai's report of Bigthana and Teresh's assassination plot (Esth 2:21-23). <strong>ʾăšer higgîḏ Mordoḵay ʿal bignəṯānāʾ wāṯereš</strong> — 'that Mordecai had informed about Bigthana and Teresh.' The pluperfect construction situates this as a past act now being retrieved from institutional memory.</p>",
    "3": "<p><strong>māh-naʿăśāh yəqār ûgəḏûllāh lə-Mordoḵay ʿal-zeh</strong> — 'What honor and dignity was given (<em>naʿăśāh</em> = was done) to Mordecai for this?' The question is the pivot of the narrative. <em>Yəqār</em> (H3366 = honor, preciousness, worth) and <em>gəḏûllāh</em> (H1420 = greatness, magnitude) together constitute the Persian court vocabulary for official recognition and advancement. The king's attendants answer: <strong>lōʾ-naʿăśāh ʿimmô dāḇār</strong> — 'nothing was done for him.' The gap between the service rendered (saving the king's life) and the reward received (nothing) is the narrative engine: the unrecompensed good deed is about to be recompensed at exactly the wrong moment for Haman.</p>",
    "4": "<p><strong>wayyōʾmer hammeleḵ mî baḥāṣēr</strong> — 'The king said, Who is in the court?' The king asks who is present at what must have been early morning (he has been awake all night reading records). <strong>wəHāmān bāʾ laḥăṣar bêṯ-hammeleḵ haḥîṣônāh</strong> — 'Haman had come to the outer court of the king's house.' The outer court (ḥāṣar haḥîṣônāh) is the public entry area. Haman is arriving precisely to request Mordecai's hanging on the gallows he constructed (5:14 — he had the 50-cubit gallows built that night). The timing: the king insomniac, records open to Mordecai's act, seeking someone to reward — and at that moment the man who intends to destroy Mordecai walks in. The Persian court's compression of coincidences is the book's theological signature.</p>",
    "5": "<p><strong>wayyōmərû naʿărê hammeleḵ ʾēlāyw hinnēh Hāmān ʿōmēḏ baḥāṣēr</strong> — 'The king's servants said, Behold, Haman is standing in the court.' The deictic particle <em>hinnēh</em> (H2009 = behold, look) — a particle of personal and surprising observation — marks the coincidence as notable. <strong>wayyōʾmer hammeleḵ yāḇōʾ</strong> — 'The king said, Let him come in.' The immediate royal invitation gives Haman access before he can report his purpose — the narrative shows the king taking the initiative in a direction entirely opposite to Haman's.</p>",
    "6": "<p><strong>wayyāḇōʾ Hāmān wayyōʾmer lô hammeleḵ māh laʿăśôṯ bāʾîš ʾăšer hammeleḵ ḥāpēṣ bîqārô</strong> — 'Haman came, and the king said to him, What should be done for the man whom the king delights to honor?' The king's question is utterly general — 'whom the king wishes to honor' — but the narrator immediately notes: <strong>wayyōʾmer Hāmān bəlibbô</strong> — 'Haman said in his heart' (<em>bəlibbô</em>, H3820 = in his heart/mind). The interior dialogue technique — showing Haman's unspoken reasoning — is the narrative's finest irony setup: <strong>ləmî yaḥpōṣ hammeleḵ laʿăśôṯ yəqār yôṯēr mimmennî</strong> — 'for whom would the king wish to honor more than me?' Haman's assumption of self-referentiality is the mechanism of his destruction: he designs the perfect honor he wishes for himself.</p>",
    "7": "<p><strong>wayyōʾmer Hāmān ʾel-hammeleḵ</strong> — 'And Haman said to the king.' What follows is Haman's proposal of the honor ceremony, elaborated across vv7-9 as an increasingly extravagant display. The fourfold honor: the royal robe, the king's horse, a royal crown on the horse's head, and proclamation through the city square. <strong>ʾîš ʾăšer hammeleḵ ḥāpēṣ bîqārô</strong> — 'the man whom the king delights to honor' — Haman repeats the king's phrase, still (in his imagination) applying it to himself. The repetition of this phrase in vv6-11 (four times total) is the structural pattern of the reversal: each repetition shifts the referent from Haman's imagined self-application to Mordecai's actual receipt.</p>",
    "8": "<p><strong>yāḇîʾû leḇûš malkûṯ ʾăšer lāḇaš-bô hammeleḵ</strong> — 'let royal robes be brought which the king has worn.' The request is for the actual garment the king wore, not a replica — an extraordinary honor that approximates royal identity. <strong>wəsûs ʾăšer rāḵaḇ ʿālāyw hammeleḵ</strong> — 'and a horse on which the king has ridden.' Again the actual royal horse, not a ceremonial equivalent. The parallelism of robe and horse — both <em>ʾăšer</em> + relative clause indicating the king's own — makes the honor the maximum possible short of actual kingship: to wear the king's robe on the king's horse is to impersonate the king in the public square.</p>",
    "9": "<p><strong>wənaṯôn hallāḇûš wəhassûs ʿal-yaḏ-ʾîš miśśārê hammelek happartemîm</strong> — 'Let the robe and the horse be given into the hand of one of the king's most noble officials.' The term <em>partemîm</em> (H6579) is a Persian loanword designating the highest-ranking nobles, the inner circle of the court. Haman designs the honor to require a senior official to personally lead the horse through the streets — making the honor a public spectacle performed by the nobility itself. <strong>wihirqîḇuhû ʿal-hassûs birḥôḇ hāʿîr wəqārəʾû ləp̄ānāyw kākāh yēʿāśeh lāʾîš ʾăšer hammeleḵ ḥāpēṣ bîqārô</strong> — 'and they should proclaim before him: Thus is done for the man whom the king delights to honor.' The town-crier announcement turns the honor into public city-wide knowledge.</p>",
    "10": "<p><strong>wayyōʾmer hammeleḵ lHāmān maher qaḥ ʾeṯ-hallāḇûš wəʾeṯ-hassûs</strong> — 'The king said to Haman: Quick, take the robe and the horse!' The adverb <em>maher</em> (H4116 = quickly, hurry) conveys royal urgency — the king is impatient to execute the plan. <strong>kaʾăšer dibbartā waʿăśēh-ḵēn ləMordoḵay hayyəhûḏî</strong> — 'as you have spoken, and do so to Mordecai the Jew.' The three words 'Mordecai the Jew' are the detonation of the irony: Haman designed the honor for himself; he must perform it for his designated victim. The title <em>hayyəhûḏî</em> (H3064 = the Jew) — the very identity marker that caused Haman's rage (3:4-6) — is placed immediately after Mordecai's name, making Haman serve the representative of the people he intended to destroy. <strong>ʾal-tappēl dāḇār mikkōl ʾăšer dibbartā</strong> — 'do not omit anything of all that you have spoken' — the king locks Haman into executing his own plan in full.</p>",
    "11": "<p><strong>wayyiqqaḥ Hāmān ʾeṯ-hallāḇûš wəʾeṯ-hassûs</strong> — 'Haman took the robe and the horse.' The subject shift — Haman as the actor performing what he designed for himself upon Mordecai — is the structural center of the reversal narrative. <strong>wayyalbiš ʾeṯ-Mordoḵay wayyarkîḇēhû birḥôḇ hāʿîr wayyiqrāʾ ləp̄ānāyw kākāh yēʿāśeh lāʾîš ʾăšer hammeleḵ ḥāpēṣ bîqārô</strong> — 'He clothed Mordecai and had him ride through the city square, and proclaimed before him: Thus is done to the man whom the king delights to honor.' The proclamation formula is used for the fourth time — but now in full actuality, with Mordecai as recipient. The repetition is a rhetorical device of reversal: the same words, spoken by the same mouth, for the opposite man.</p>",
    "12": "<p><strong>wayyāšāḇ Mordoḵay ʾel-šaʿar hammeleḵ</strong> — 'Mordecai returned to the king's gate.' The return to the gate — his post (Esth 2:19,21; 3:2) — signals that Mordecai does not seek to leverage the honor into advancement. The gate (<em>šaʿar</em>, H8179) is where he belongs and where he returns. <strong>wHāmān nitdahar ʾel-bêṯô</strong> — 'Haman hurried to his house, mourning.' <em>Nitdahar</em> (H1765, niphal = to hasten, rush) and the participle <em>ʾāḇēl</em> (H57 = mourning, in grief) — the exact opposite of the public honor procession. The reversal is complete: Mordecai honored in public, Haman hiding at home in mourning.</p>",
    "13": "<p><strong>wayyəsappēr Hāmān ləZereš ʾišṯô ûlə-ḵol-ʾōhăḇāyw ʾēṯ kol-ʾăšer qārāhû</strong> — 'Haman told his wife Zeresh and all his friends everything that had happened to him.' The same advisors who proposed the gallows (5:14) now deliver a counter-verdict. <strong>wayyōmərû lô ḥăḵāmāyw wəZereš ʾišṯô ʾim mizzareʿ hayyəhûḏîm Mordoḵay ʾăšer haḥillôṯā linpōl ləp̄ānāyw lōʾ-ṯûḵal lô wənāpôl tippōl ləp̄ānāyw</strong> — 'His advisors and Zeresh his wife said to him: If Mordecai before whom you have begun to fall is of Jewish descent, you will not overcome him but will fall before him.' The conditional sentence <em>ʾim mizzereʿ hayyəhûḏîm</em> (if from the seed of the Jews) implies that the Jews are recognized as a people under supernatural protection. <em>Nāpôl tippōl</em> (infinitive absolute + finite verb = you will certainly fall) is the emphatic construction. His own household pronounces the prophecy of his defeat.</p>",
    "14": "<p><strong>ʿôḏām mədabbrîm ʿimmô</strong> — 'While they were still speaking with him' — the temporal clause creates urgency: before the counsel can be absorbed or responded to. <strong>wəsārîsê hammeleḵ higgîʿû wayyabhîlû lhāḇîʾ ʾeṯ-Hāmān ʾel-hammišṯeh ʾăšer ʿāśəṯāh ʾEsṯēr</strong> — 'the king's eunuchs arrived and hurried Haman to the banquet that Esther had prepared.' <em>Bahel</em> (H926, piel = to hurry, cause to hurry) — the same verb as v10's 'quick!' — urgency is the narrative rhythm of this chapter. Haman is pulled from ominous counsel to the banquet that will be his unraveling, without time to process what his household has just told him.</p>"
  },
  "7": {
    "1": "<p><strong>wayyāḇōʾ hammeleḵ wəHāmān lišṯôṯ ʾim-ʾEsṯēr hammalkāh</strong> — 'The king and Haman came to drink with Esther the queen.' The verb <em>šāṯāh</em> (H8354 = to drink) governs the social frame: this is the 'drinking banquet' (<em>mišṯeh</em>, from the same root) that Esther had prepared. The pairing of the king and Haman as joint guests at the queen's table is the formal setting for the denouement. The repetition of the banquet setting (cf. 5:4-8) doubles the dramatic tension: Esther's first banquet produced a second invitation; the second banquet will produce the revelation she has been preparing.</p>",
    "2": "<p><strong>wayyōʾmer hammeleḵ ləʾEsṯēr gam bayyôm haššēnî bəmišṯēh hayyāyin</strong> — 'And the king said to Esther again on the second day at the wine banquet.' <strong>māh šəʾēlāṯēḵ ʾEsṯēr hammalkāh wəṯinnāṯēn lāḵ ûmāh baqqāšāṯēḵ ʿaḏ-ḥăṣî hammalkûṯ wəṯēʿāś</strong> — 'What is your request, Queen Esther? It shall be granted you. What is your petition? Even to half the kingdom, it shall be done.' The Persian royal formula <em>ʿaḏ-ḥăṣî hammalkûṯ</em> ('up to half the kingdom') appears three times in Esther (5:3, 5:6, 7:2) — a rhetorical hyperbole of unlimited royal generosity. The irony is that what Esther will request is not territory or wealth but lives, which no royal formula can technically grant without overturning a standing decree.</p>",
    "3": "<p><strong>wattagʿan ʾEsṯēr hammalkāh watōʾmar ʾim-māṣāʾṯî ḥēn bəʿênêḵā hammeleḵ</strong> — 'And Queen Esther answered and said: If I have found favor in your eyes, O king.' The conditional clause <em>ʾim-māṣāʾṯî ḥēn</em> (if I have found favor) is Esther's standard rhetorical opener — deferential, petition-form language (cf. 5:8; 8:5). <strong>wəʾim-ʿal-hammeleḵ ṭôḇ</strong> — 'and if it pleases the king' — the second condition stacks the deference. <strong>tinnāṯen-lî napšî bišʾēlāṯî wəʿammî bəḇaqqāšāṯî</strong> — 'let my life (<em>napšî</em>) be given to me at my petition and my people (<em>ʿammî</em>) at my request.' <em>Nepsheš</em> (H5315 = soul, life, living being) is the first-person self-presentation: Esther has identified herself with her people's fate. The paired structure — my life / my people — makes her petition both personal and communal.</p>",
    "4": "<p><strong>kî nimkarnû ʾănî wəʿammî lhašmîḏ lahărôg ûləʾabbēḏ</strong> — 'For we have been sold — I and my people — to be destroyed, to be killed, and to be annihilated.' <em>Māḵar</em> (H4376, niphal = to be sold) picks up the commercial language of Haman's decree-purchase (3:9 — 'I will pay 10,000 talents'). <em>Lhašmîḏ lahărôg ûləʾabbēḏ</em> — the three-term genocidal formula (H8045 + H2026 + H6) repeats the decree's language from 3:13 exactly, making the connection unmistakable. <strong>wəʾilû laʿăḇāḏîm ûlišpāḥôṯ nimkarnû heḥěrašṯî</strong> — 'If we had merely been sold as slaves, male and female, I would have been silent.' Esther's rhetorical move: she would not trouble the king for the loss of freedom (economic harm to the king), but extinction cannot be borne in silence. <em>Heḥěrašṯî</em> (H2790, hiphil = to be silent, hold the tongue) — the contrast between silent acceptance of slavery and the impossibility of silence before genocide.</p>",
    "5": "<p><strong>wayyōʾmer hammeleḵ ʾAḥašwērôš wayyōʾmer ləʾEsṯēr hammalkāh mî hûʾ zeh wəʾê-zeh hûʾ ʾăšer-məlāʾô libbô laʿăśôṯ kēn</strong> — 'King Ahasuerus said, and he said to Queen Esther: Who is he, and where is he who has dared to do this?' The doubled verb <em>wayyōʾmer</em> (he said... and he said) is unusual — possibly indicating that the king was stunned into a pause, or reflecting the intensity of his reaction. The phrase <em>ʾăšer-məlāʾô libbô</em> — 'whose heart has filled him (to do this)' = 'who dared' — uses the heart-fullness idiom for audacity or presumption. The king's outrage is oriented toward the actor, not yet identified: 'who did this?'</p>",
    "6": "<p><strong>watōʾmer ʾEsṯēr ʾîš ṣar wəʾôyēḇ Hāmān hārāʿ hazzeh</strong> — 'Esther said: A man of distress and an enemy — this wicked Haman!' The paired accusation formula <em>ṣar wəʾôyēḇ</em> (H6887 = adversary/one who presses + H341 = enemy) is the full legal indictment: not merely a rival but an active enemy. <em>Hāmān hārāʿ hazzeh</em> — 'this wicked Haman' — the demonstrative <em>hazzeh</em> (this) used deictically to point at the person present. The naming comes after the characterization: first the moral category, then the personal identification. <strong>wəHāmān nib'at millipnê hammeleḵ wəhammalkāh</strong> — 'and Haman was terrified before the king and the queen.' <em>Bāʿat</em> (H1204, niphal = to be terrified, startled) — the instantaneous fear-response upon being named.</p>",
    "7": "<p><strong>wəhammeleḵ qām baḥămāṯô mimmišṯēh hayyāyin ʾel-gannath habbîṯān</strong> — 'And the king rose in his wrath from the wine banquet to the palace garden.' <em>Ḥēmāh</em> (H2534 = wrath, burning anger) — the same word used of the king's anger at Vashti (1:12) and at the first report of Haman's plot against Mordecai (after Esther's revelation). <em>Gannath habbîṯān</em> — 'the garden of the palace' (H1594 + H1055 = the enclosed garden attached to the palace complex). The king's withdrawal to the garden is a moment of processing: he has condemned Haman but not yet decided the execution. <strong>wəHāmān ʿāmaḏ ləḇaqqēš ʿal-napšô mēʾEsṯēr hammalkāh</strong> — 'and Haman stood to beg for his life from Esther the queen.' <em>Baqqēš ʿal-nepheš</em> (to seek for one's life) — the ultimate reversal: the man who sought to destroy the queen's people now begs the queen for his own life.</p>",
    "8": "<p><strong>wəhammeleḵ šāḇ migan habbîṯān ʾel-bêṯ mišṯēh hayyāyin</strong> — 'And the king returned from the palace garden to the house of the wine banquet.' The return from garden to banquet-room signals that the king has reached his decision. <strong>wəHāmān nōpēl ʿal-hammittāh ʾăšer ʾEsṯēr ʿālêhā</strong> — 'and Haman had fallen upon the couch where Esther was.' <em>Nāpal</em> (H5307 = to fall, throw oneself) in the supplication position: prostrating at the queen's reclining couch in the Persian banquet setting. The king's interpretation: <strong>hăgam liḵbôš ʾeṯ-hammalkāh ʿimmî babbāyiṯ</strong> — 'Is he also going to violate the queen in my house?' <em>Kāḇaš</em> (H3533 = to subdue, force, violate) — the king's reading of Haman's prostration as sexual assault. Whether intentional misreading or genuine misunderstanding, the king's declaration seals Haman's fate. <strong>hadāḇār yaṣāʾ mippî hammeleḵ ûpənê Hāmān ḥāp̄û</strong> — 'the word went out of the king's mouth and they covered Haman's face.' <em>Ḥāp̄û</em> (H2645, piel = to cover) — the covering of the condemned man's face was an ancient execution protocol; Haman is effectively dead at this moment.</p>",
    "9": "<p><strong>wayyōʾmer Harbônāh ʾaḥaḏ min-hassārîsîm lipnê hammeleḵ</strong> — 'Then Harbona, one of the eunuchs in the king's presence, said.' Harbona is one of the seven eunuchs listed in 1:10. His intervention provides the information that triggers the execution method. <strong>gam hinnēh-hāʿēṣ ʾăšer-ʿāśāh Hāmān ləMordoḵay ʾăšer dibbēr-ṭôḇ ʿal-hammeleḵ ʿōmēḏ bêṯ Hāmān gāḇōah ḥămiššîm ʾammāh</strong> — 'Also, look — the tree/gallows that Haman made for Mordecai, who spoke good for the king, stands in Haman's house, 50 cubits high.' <em>Hāʿēṣ</em> (H6086 = tree, wood, wooden stake/gallows) — the very instrument Haman constructed for Mordecai becomes his own execution apparatus. The fifty-cubit height (approximately 75 feet) signals that it was visible above the city's rooflines — designed for maximum public spectacle. The subordinate clause 'who spoke good for the king' is Harbona's reminder of Mordecai's unrewarded loyalty. <strong>wayyōʾmer hammeleḵ tālethu ʿālāyw</strong> — 'And the king said: Hang him on it.'</p>",
    "10": "<p><strong>wayyillu ʾeṯ-Hāmān ʿal-hāʿēṣ ʾăšer-hēḵîn ləMordoḵay</strong> — 'And they hanged Haman on the gallows that he had prepared for Mordecai.' The sentence is structured so that the relative clause 'which he had prepared for Mordecai' immediately follows the description of the execution — the instrument of intended murder becomes the instrument of actual execution. <em>Kûn</em> (H3559, hiphil = to prepare, establish, make ready) in the perfect tense emphasizes that it was Haman's own preparation, completed and ready. <strong>waḥămaṯ hammeleḵ šāḵāḵāh</strong> — 'And the king's wrath subsided.' <em>Šāḵak</em> (H7918 = to become quiet, subside, be appeased) — the same verb as the ocean subsiding after Jonah's casting overboard (Jon 1:11,12). The king's wrath is satisfied by the execution that the king's own servant provided the means for, using the perpetrator's own construction.</p>"
  },
  "8": {
    "1": "<p><strong>bayyôm hahûʾ nāṯan hammeleḵ ʾAḥašwērôš ləʾEsṯēr hammalkāh ʾeṯ-bêṯ Hāmān ṣōrēr hayyəhûḏîm</strong> — 'On that day King Ahasuerus gave to Queen Esther the house of Haman the enemy of the Jews.' <em>Bêṯ Hāmān</em> (the house/estate of Haman) — the entire household property, which passed to the crown upon execution of a traitor. The appositional phrase <em>ṣōrēr hayyəhûḏîm</em> (enemy/adversary of the Jews, H6887) accompanies Haman's name as a permanent epithet; it appears first at 3:10 and recurs to ensure the reader reads every subsequent reference to Haman through this lens. <strong>ûMordoḵay bāʾ lipnê hammeleḵ kî-higgîḏāh ʾEsṯēr māh hûʾ-lāh</strong> — 'Mordecai came before the king, for Esther had told what he was to her.' The disclosure of the kinship relationship (Esther's cousin/guardian) is now made explicit to the king for the first time.</p>",
    "2": "<p><strong>wayyāsar hammeleḵ ʾeṯ-ṭabbaʿtô ʾăšer hĕʿĕḇîr mēHāmān wayyittənāh ləMordoḵay</strong> — 'The king removed his signet ring (<em>ṭabbaʿat</em>, H2885) which he had taken back from Haman and gave it to Mordecai.' The signet ring is the instrument of royal authority — Haman received it to seal the destruction decree (3:10); now Mordecai receives it as the king's authorized agent. The transfer of the ring formally transfers Haman's position. <strong>wataśem ʾEsṯēr ʾeṯ-Mordoḵay ʿal-bêṯ Hāmān</strong> — 'and Esther set Mordecai over the house of Haman.' The estate granted by the king is placed under Mordecai's administration by Esther — a double authority structure: the king grants to Esther, Esther delegates to Mordecai, completing the reversal from the sequence in chapter 3 where Haman received the king's ring and authority.</p>",
    "3": "<p><strong>watṯōsep̄ ʾEsṯēr watḏabbēr lip̄nê hammeleḵ wattippōl lip̄nê raglāyw watteḇk</strong> — 'Esther spoke again before the king and fell at his feet and wept.' <em>Wattippōl lip̄nê raglāyw</em> (fell before his feet) — prostration is the most supplicatory posture possible, more than the extended scepter approach of 5:2. The weeping (<em>bāḵāh</em>, H1058) is not performed but genuine: the decree that threatens her people remains in force despite Haman's death. <strong>ûtəḥannen-lô ləhaʿăḇîr ʾeṯ-rāʿaṯ Hāmān hāʾăgāgî wəʾeṯ-maḥăšaḇtô ʾăšer ḥāšaḇ ʿal-hayyəhûḏîm</strong> — 'and implored him to put away the evil of Haman the Agagite and the plan that he had planned against the Jews.' <em>Ḥāšaḇ</em> (H2803 = to plan, reckon, think): the plan (maḥăšebet) that Haman had thought out is now to be overturned. The Agagite epithet (H91) connects Haman to Agag king of Amalek (1 Sam 15) — locating the conflict within the long Amalekite-Israelite enmity.</p>",
    "4": "<p><strong>wayyôšeṭ hammeleḵ ləʾEsṯēr ʾeṯ-šarḇîṭ hazzāhāḇ</strong> — 'The king extended to Esther the golden scepter.' The extension of the golden scepter (H8275, the same act as 5:2) signals that the queen's unsummoned approach is accepted again. The repetition of the scepter scene emphasizes that Esther's access to the king is never guaranteed — each entry into the inner court is an act of petition requiring royal acceptance. <strong>watāqam ʾEsṯēr wattaʿămod lip̄nê hammeleḵ</strong> — 'and Esther arose and stood before the king.' The movement from prostration (v3) to standing (v4) enacts the transition from mourning petition to formal request.</p>",
    "5": "<p><strong>watōʾmer ʾim-ʿal-hammeleḵ ṭôḇ wəʾim-māṣāʾṯî ḥēn ləp̄ānāyw</strong> — 'If it please the king and if I have found favor before him.' Esther's third banquet-approach formula, stacking conditions. <strong>wənākôn haddāḇār lip̄nê hammeleḵ wəṭôḇāh ʾănî bəʿênāyw</strong> — 'and the thing seems right to the king and I am good in his eyes.' The fourfold condition — king's pleasure, found favor, right in his estimation, good in his sight — represents maximum deference in Persian court protocol. <strong>yikkāṯēḇ ləhāšîḇ ʾeṯ-hassəp̄ārîm maḥăšeḇeṯ Hāmān ben-Hammedāṯāʾ hāʾăgāgî ʾăšer kāṯaḇ ləʾabbēḏ ʾeṯ-hayyəhûḏîm ʾăšer bəḵol-məḏînôṯ hammeleḵ</strong> — 'let it be written to revoke the letters of the plan of Haman ... which he wrote to destroy the Jews in all the king's provinces.' <em>Lhāšîḇ</em> (H7725, hiphil = to cause to return, revoke) — the request is not merely to nullify but to return/recall the letters; whether a Persian decree could be formally overturned is the legal complexity Esther is navigating.</p>",
    "6": "<p><strong>kî êḵāḵāh ʾûḵal wərāʾîṯî bərāʿāh ʾăšer-yimṣāʾ ʾeṯ-ʿammî</strong> — 'For how can I bear to see the disaster that will come upon my people?' <em>Bərāʿāh</em> (H7451 = evil, disaster, calamity) — the word that will befall her people is <em>rāʿāh</em>, the covenant-disaster term. <strong>wəêḵāḵāh ʾûḵal wərāʾîṯî bəʾăḇōḏan môladtî</strong> — 'and how can I bear to see the destruction of my kindred (<em>môladtî</em>)?' <em>Môledet</em> (H4138 = birth, lineage, kindred — those born from the same family line) is the kinship word: Esther's appeal is not abstract but personal and genealogical. The doubled rhetorical question (<em>êḵāḵāh ʾûḵal</em> + <em>wəêḵāḵāh ʾûḵal</em>) intensifies the emotional impossibility of passive acceptance.</p>",
    "7": "<p><strong>wayyōʾmer hammeleḵ ʾAḥašwērôš ləʾEsṯēr hammalkāh ûləMordoḵay hayyəhûḏî</strong> — 'King Ahasuerus said to Queen Esther and to Mordecai the Jew.' The king now addresses Esther and Mordecai together — the official couple in his administration. <strong>hinnēh bêṯ Hāmān nāṯattî ləʾEsṯēr wəʾôṯô tālû ʿal-hāʿēṣ</strong> — 'Behold, I have given the house of Haman to Esther, and they have hanged him on the gallows.' The king rehearses what has already been done — the estate given, the man executed — to frame what cannot yet be done: overturning a sealed royal decree. <strong>taḥat ʾăšer šālaḥ yāḏô bayyəhûḏîm</strong> — 'because he sent his hand against the Jews' — the idiom <em>šālaḥ yāḏ</em> (sent the hand) denoting violent action (cf. Neh 13:21).</p>",
    "8": "<p><strong>wəʾattem kiṯḇû ʿal-hayyəhûḏîm kaṭṭôḇ bəʿênêḵem bəšem hammeleḵ</strong> — 'And you, write about the Jews as seems good to you in the name of the king.' The authorization is given to Mordecai and Esther to compose a second decree, but the structural problem is stated explicitly: <strong>kî-kiṯāḇ ʾăšer-niḵtaḇ bəšem-hammeleḵ wəneḥtôm bəṭabbaʿat hammeleḵ ʾên ləhāšîḇ</strong> — 'for an edict written in the king's name and sealed with the king's ring cannot be revoked.' The Persian legal principle of the irrevocability of sealed royal decrees (cf. Dan 6:8,12,15) creates the legal constraint: the original decree cannot be nullified, only countered. The new decree will authorize the Jews to defend themselves, effectively rendering the original decree ineffective in practice without formally rescinding it.</p>",
    "9": "<p><strong>wayyiqqārəʾû sōp̄ərê hammeleḵ bāʿēṯ hahîʾ baḥōḏeš haššəlîšî hûʾ-ḥōḏeš sîwān</strong> — 'The king's scribes were summoned at that time in the third month, which is the month of Sivan.' The third month Sivan (May–June) is approximately two months after Nisan/Abib (month 1) when Haman cast lots (3:7). The date is significant: on the 23rd of Sivan, the counter-decree is issued. <strong>wayyikkāṯēḇ kəḵol-ʾăšer-ṣiwwāh Mordoḵay ʾel-hayyəhûḏîm wəʾel hāʾăḥašdarpənîm wəhappaḥôṯ wəśārê hammĕḏînôṯ ʾăšer mēhōddû wəʿaḏ-kûš</strong> — 'and it was written according to all that Mordecai commanded, to the Jews and to the satraps and governors and officials of the provinces from India to Ethiopia.' The administrative reach (127 provinces, 1:1) mirrors the scope of the original threat decree (3:12-14).</p>",
    "10": "<p><strong>wayyiḵtōḇ bəšēm hammeleḵ ʾAḥašwērôš wayyaḥtōm bəṭabbaʿat hammeleḵ</strong> — 'He wrote in the name of King Ahasuerus and sealed it with the king's ring.' The parallel to 3:12 (<em>wayyikkāṯēḇ</em>/<em>wayyaḥtōm</em>) makes the formal equivalence explicit: Mordecai's counter-decree has exactly the same legal weight as Haman's original decree, sealed with the same ring. <strong>wayyišlaḥ səp̄ārîm bəyaḏ hārāṣîm bassûsîm rōḵəḇê hārekeš hāʾăḥaštranim bənê hārammāḵîm</strong> — 'and sent letters by couriers on horseback, on swift horses bred from the royal stud.' The repeated emphasis on the speed of the horses (H7409 + H7424 = relay-horse breeds of the Persian royal postal system, the <em>angareion</em>) signals urgency: the counter-decree must reach every province before the original.</p>",
    "11": "<p><strong>ʾăšer nāṯan hammeleḵ layyəhûḏîm ʾăšer bəḵol-ʿîr wāʿîr lihhāqāhēl wəlaʿămōḏ ʿal-napšām</strong> — 'That the king permitted the Jews who were in every city to assemble and stand for their lives.' <em>Lihāqāhēl</em> (H6950, niphal = to assemble, gather together) and <em>laʿămōḏ ʿal-napšām</em> (to stand for their lives/selves) are the two rights granted: assembly and self-defense. The new decree does not cancel the old but creates a counter-authorization: the Jews may do to those who attack them exactly what the original decree authorized others to do to the Jews. <strong>lhašmîḏ wlaharōg ûlaʾabbēḏ</strong> — 'to destroy, to kill, and to annihilate' — the exact three-term formula of 3:13, now applied in reverse direction. The narrative irony: the language of intended genocide becomes the language of authorized defense.</p>",
    "12": "<p><strong>bəyôm ʾeḥāḏ bəḵol-məḏînôṯ hammeleḵ ʾAḥašwērôš bišlōšāh ʿāśār ləḥōḏeš šənêm ʿāśār hûʾ-ḥōḏeš ʾăḏār</strong> — 'On one day in all the provinces of King Ahasuerus, on the thirteenth of the twelfth month, which is the month of Adar.' The specific date — 13 Adar — is fixed by Haman's lot-casting from 3:7 (which determined the month of Adar as the time for the destruction). The date thus remains unchanged: only the nature of the event on that day has been reversed by the counter-decree. Both decrees converge on the same calendar day: the day Haman selected for the Jews' destruction becomes the day of Jewish survival and victory.</p>",
    "13": "<p><strong>paṯšegen hakkəṯāḇ lhinnāṯen dāṯ bəḵol-məḏînāh ûməḏînāh</strong> — 'A copy of the writing was to be issued as a law in every province.' <em>Paṯšegen</em> (H6572) is a Persian loanword (Old Persian *patiša-ka = copy/transcript) used in Esther 3:14 and 4:8 as well — the formal administrative term for the distributed copies of the royal decree. <strong>gālûy ləḵol-hāʿammîm wlihyôṯ hayyəhûḏîm ʿăṯûḏîm layyôm hazzeh</strong> — 'proclaimed to all peoples so that the Jews would be ready on that day.' <em>ʿĀṯûḏ</em> (H6264 = ready, prepared) — the Jews are authorized to prepare themselves militarily. The counter-decree produces readiness rather than vulnerability.</p>",
    "14": "<p><strong>hārāṣîm rōḵəḇê hārekeš hāʾăḥaštranim yaṣəʾû məbōhālîm ûḏəḥûpîm bidiḇar hammeleḵ</strong> — 'The couriers riding the swift royal horses went out hurriedly and pressed on by the king's command.' <em>Məbōhālîm</em> (H926, pual = hurried, rushed) and <em>dəḥûpîm</em> (H1765, qal = pressed/urged forward) together depict the maximum speed of the Persian postal system. <strong>wəhaddāṯ nittənāh bəšûšan habbîrāh</strong> — 'and the edict was issued in Susa the citadel.' The decree flows outward from the capital to the whole empire — the same spatial movement as 3:15.</p>",
    "15": "<p><strong>ûMordoḵay yāṣāʾ millip̄nê hammeleḵ biliḇûš malkûṯ tēḵēlet wāḥûr wăʿăṭeret zāhāḇ gəḏôlāh wətakrîḵ bûṣ wəʾargāmān</strong> — 'Mordecai went out from before the king in royal clothing of blue and white, and with a great golden crown, and a garment of fine linen and purple.' The colors — <em>tēḵēlet</em> (H8504 = blue-violet, the color of the priestly garments, Exod 25:4) and <em>wāḥûr</em> (H2353 = white, fine white linen) — are not merely Persian court colors but carry the association of priestly and tabernacle textiles. Mordecai's public appearance in royal garments is the full reversal of 4:1 where he wore sackcloth and ashes. <strong>wəhāʿîr šûšān ṣāhălāh wəśāmēḥāh</strong> — 'and the city of Susa shouted for joy and was glad.' The city that was confused and disturbed at the original decree (3:15 — <em>wəhāʿîr šûšān nāḇôḵāh</em>) is now rejoicing.</p>",
    "16": "<p><strong>layyəhûḏîm hāyəṯāh ʾôrāh wəśimḥāh wəśāśōn wîqār</strong> — 'For the Jews there was light and gladness and joy and honor.' The four-word summary of the reversal uses a vocabulary of blessing: <em>ʾôrāh</em> (H219 = light — the metaphor for divine favor and life, Ps 27:1), <em>śimḥāh</em> (H8057 = gladness), <em>śāśōn</em> (H8342 = joy, the word used in the great joy of the feasts), <em>wîqār</em> (H3366 = honor, worth). These four nouns are the positive reversal of the four-word destruction formula from 3:13 (<em>lhašmîḏ lahărōg ûləʾabbēḏ</em>). The word-for-word opposition is structurally deliberate: destruction/killing/annihilation/plunder → light/gladness/joy/honor.</p>",
    "17": "<p><strong>ûḇəḵol-məḏînāh ûməḏînāh ûḇəḵol-ʿîr wāʿîr məqôm ʾăšer diḇar-hammeleḵ wədāṯô maggîaʿ śimḥāh wəśāśōn layyəhûḏîm mišṯeh wəyôm ṭôḇ</strong> — 'In each and every province and city, wherever the king's edict and command reached, there was gladness and joy among the Jews, a feast and a holiday.' The repetition of the distribution formula — every province, every city — mirrors the distribution of the first decree (3:14-15) to emphasize that the reversal is as total and complete as the original threat. <strong>wərabbîm mēʿammê hāʾāreṣ miṯyahăḏîm kî-nāpal paḥaḏ-hayyəhûḏîm ʿălêhem</strong> — 'and many of the peoples of the land declared themselves Jews (<em>miṯyahăḏîm</em>, H3054), because fear of the Jews had fallen upon them.' <em>Hiṯyahēḏ</em> is a hapax — the unique denominative verb meaning 'to Judaize, declare oneself a Jew.' The fear (<em>paḥaḏ</em>, H6343) of the Jews is the reversal of the Jews' fear: those who feared now cause fear.</p>"
  },
  "9": {
    "1": "<p><strong>ûḇišnêm ʿāśār ḥōḏeš hûʾ-ḥōḏeš ʾăḏār bišlōšāh ʿāśār yôm bô</strong> — 'And in the twelfth month, which is the month of Adar, on the thirteenth day of it.' The date formula opens the battle narrative with precision: the day Haman chose by lot in 3:7 (from the first month of the year through all twelve months, the lot fell on Adar 13) is now the day of the Jews' counter-defense. <strong>ʾăšer higgîaʿ diḇar-hammeleḵ wədāṯô laʿăśôṯ bô</strong> — 'when the word of the king and his edict were about to be executed.' Both decrees are operative simultaneously on this day: the original decree (destruction of Jews) and the counter-decree (authorization of self-defense). <strong>bəyôm ʾăšer śibərû ʾôyəḇê hayyəhûḏîm lišlôṭ bāhem wənāhăp̄ôḵ hûʾ ʾăšer yišlְṭû hayyəhûḏîm hēmmāh bəśōnəʾêhem</strong> — 'on the day when the enemies of the Jews hoped to overpower them, but it was reversed (<em>nāhăp̄ôḵ</em>): the Jews themselves overpowered those who hated them.' <em>Hāp̄ak</em> (H2015 = to turn over, reverse, overturn) — the verb of reversal used of the Sodom overthrow (Gen 19:25), the sea-crossing (Exod 14:27), and divine repentance. The entire narrative program of Esther is compressed into this one verb.</p>",
    "2": "<p><strong>niqqahălû hayyəhûḏîm bəʿārêhem bəḵol-məḏînôṯ hammeleḵ ʾAḥašwērôš lišlōaḥ yāḏ bimbaqqəšê rāʿāṯām</strong> — 'The Jews assembled in their cities throughout all the provinces of King Ahasuerus to lay hands on those who sought their harm.' <em>Lišlōaḥ yāḏ</em> (to send/lay the hand, i.e., to attack) — the same idiom used of Haman's intended violence against the Jews. The Jews' legal authorization mirrors Haman's action precisely: they do to their attackers what Haman's decree authorized to be done to them. <strong>wəʾîš lōʾ-ʿāmaḏ lip̄nêhem kî-nāpal paḥdām ʿal-kol-hāʿammîm</strong> — 'and no one could withstand them, for dread of them had fallen on all the peoples.' <em>Nāpal paḥad</em> (fear fell) — the same formula as 8:17 (fear of the Jews fell upon the peoples) and echoes the Rahab passage (Josh 2:9 — the same formula used of Israel's arrival in Canaan).</p>",
    "3": "<p><strong>wəḵol-śārê hammĕḏînôṯ wəhāʾăḥašdarpənîm wəhappaḥôṯ wəʿōśê hamməlāʾḵāh ʾăšer lammeleḵ mənaśśəʾîm ʾeṯ-hayyəhûḏîm</strong> — 'All the officials of the provinces, the satraps, the governors, and those doing the king's business supported the Jews.' <em>Nāśāʾ</em> (H5375 = to lift, support, favor) — the provincial administration's active support is not merely passive tolerance but active facilitation. <strong>kî-nāpal paḥaḏ Mordoḵay ʿălêhem</strong> — 'for dread of Mordecai had fallen on them.' The fear-formula is now personalized to Mordecai: the political actor whose elevation and counter-decree created the new situation.</p>",
    "4": "<p><strong>kî-gāḏôl Mordoḵay bêṯ hammeleḵ wəšimʿô hôlēḵ bəḵol-hammĕḏînôṯ kî hāʾîš Mordoḵay hôlēḵ wəgāḏôl</strong> — 'for Mordecai was great in the king's house, and his fame spread throughout all the provinces, for the man Mordecai was growing greater and greater.' The doubled greatness statement — <em>gāḏôl</em> in both clauses, with <em>hôlēḵ wəgāḏôl</em> (going/becoming ever greater, a Hebrew idiom for continuous progression) — signals that Mordecai's position has reached empire-wide recognition. The phrase <em>hôlēḵ wəgāḏôl</em> uses the participle of motion (<em>hālaḵ</em>, to walk) with <em>gāḏôl</em> as a complementary predicate — a standard Hebrew idiom for continuous increase (cf. Gen 26:13; 2 Sam 3:1).</p>",
    "5": "<p><strong>wayyakkû hayyəhûḏîm bəḵol-ʾôyəḇêhem makkat-ḥereḇ wəhereḡ wəʾăḇāḏan wayyaʿăśû bəśōnəʾêhem kirṣônām</strong> — 'The Jews struck all their enemies with the stroke of the sword, killing and destroying, and they did to those who hated them as they pleased.' <em>Makkat-ḥereḇ</em> (H4347 = blow of the sword) — the military engagement idiom. <em>Wəhereḡ wəʾăḇāḏan</em> (killing and destroying) — two of the three terms from the original destruction decree (3:13), now performed by the Jews against their attackers. <em>Kirṣônām</em> (H7522 = according to their will/pleasure) — the Jews act with full authorization and capacity.</p>",
    "6": "<p><strong>ûḇəšûšan habbîrāh hārgû hayyəhûḏîm wəʾabbēḏ ḥămiššah mēʾôṯ ʾîš</strong> — 'In Susa the citadel the Jews killed and destroyed 500 men.' The specific number in the capital — 500 — is followed by the list of Haman's ten sons (vv7-9), making the capital's battle focused on the Agagite family that originated the threat. The killing in the capital is the resolution of the central conflict; the deaths in the provinces (vv12-15) are the extension.</p>",
    "7": "<p><strong>wəʾēṯ Paršandāṯāʾ wəʾēṯ Dalp̄ôn wəʾēṯ ʾAspāṯāʾ</strong> — 'and Parshandatha and Dalphon and Aspatha.' The list of Haman's ten sons begins here and continues through v9. All ten names are Persian or non-Hebrew in origin — most scholars identify them as Persian or possibly Elamite names. The enumeration of ten sons in three verses (7-9) creates a litany of the destroyed Agagite line; the Amalekite enemy, whose extermination Saul failed to complete (1 Sam 15), is now fully eliminated.</p>",
    "8": "<p><strong>wəʾēṯ Pôraṯāʾ wəʾēṯ ʾAḏalyāʾ wəʾēṯ ʾArîḏāṯāʾ</strong> — 'and Poratha and Adalia and Aridatha.' The continuation of the son-list. <em>ʾAḏalyāʾ</em> has been proposed to contain a theophoric element (-yah), though this is debated. The names' foreignness marks the sons as unambiguously Persian-Agagite, not Jewish.</p>",
    "9": "<p><strong>wəʾēṯ Parmašṯāʾ wəʾēṯ ʾArîsay wəʾēṯ ʾArîḏay wəʾēṯ Wayzāṯāʾ</strong> — 'and Parmashta and Arisai and Aridai and Vaizatha.' The final four sons complete the ten. The talmudic tradition (Megillah 16b) notes that the scribes wrote all ten names in a single column (rather than across a line), and that the three letters vav (ו) in three names should be written large — encoding a visual memory-device for the tradition of the ten hanged sons. The ten sons are killed but not plundered (v10), echoing Saul's failure: here Israel does what Saul did not.</p>",
    "10": "<p><strong>ʿăśeṯ bənê-Hāmān ben-Hammedāṯāʾ ṣōrēr hayyəhûḏîm hāragû ûḇabizzāh lōʾ šālāḥû ʾeṯ-yāḏām</strong> — 'the ten sons of Haman son of Hammedatha, the enemy of the Jews, they killed, but on the plunder they did not lay their hands.' The refusal of plunder is the detail that most clearly echoes the Amalekite war of 1 Sam 15 — where Saul and the people kept the plunder against YHWH's command (ḥērem), leading to Saul's rejection. Here the Jews voluntarily refuse the plunder that the counter-decree authorized (8:11), demonstrating that their purpose is not enrichment but survival. The contrast is a deliberate narrative correction of Saul's failure.</p>",
    "11": "<p><strong>bayyôm hahûʾ bāʾ mispar hahaRûgîm bəšûšan habbîrāh lip̄nê hammeleḵ</strong> — 'On that day the number of those killed in Susa the citadel was brought before the king.' The formal report to the king maintains the narrative's bureaucratic framework — even the battle results are processed through Persian administrative procedure. <strong>wayyōʾmer hammeleḵ ləʾEsṯēr hammalkāh</strong> — 'And the king said to Queen Esther.' The king's immediate response is to inform Esther, centering her in the narrative even after the action has shifted to the military sphere.</p>",
    "12": "<p><strong>bəšûšan habbîrāh hārgû hayyəhûḏîm wəʾabbēḏ ḥămiššāh mēʾôṯ ʾîš wəʾēṯ ʿăśeṯ bənê-Hāmān bišʾār məḏînôṯ hammeleḵ māh ʿāśû</strong> — 'In Susa the citadel the Jews have killed 500 men and the ten sons of Haman; in the remaining provinces of the king what have they done?' The king's rhetorical question acknowledges that the full scope of the battle is beyond even his immediate knowledge — the empire is too large for same-day reporting. <strong>ûmah-šəʾēlāṯēḵ wəyinnāṭen lāḵ ûmāh-baqqāšāṯēḵ ʿôḏ wəṯēʿāś</strong> — 'What further is your request and it shall be granted, and what more is your petition and it shall be done.' The king's unlimited offer (the royal formula) is repeated — but now Esther has already achieved the primary goal; her second request is for an additional day.</p>",
    "13": "<p><strong>watōʾmer ʾEsṯēr ʾim-ʿal-hammeleḵ ṭôḇ yinnāṯēn gam-māḥār layyəhûḏîm ʾăšer bəšûšān laʿăśôṯ kədāṯ hayyôm</strong> — 'Esther said: If it pleases the king, let it be granted to the Jews who are in Susa to do tomorrow also according to the edict of today.' The additional day request is for Susa specifically — the capital, where the political opponents (Haman's allies? Agagite sympathizers?) are concentrated. <strong>wəʾēṯ ʿăśeṯ bənê-Hāmān yitlû ʿal-hāʿēṣ</strong> — 'and let the ten sons of Haman be hanged on the gallows.' Though already killed (vv7-9), the public hanging of their bodies is requested as deterrent display — ANE practice of exhibiting slain enemies publicly (cf. Josh 10:26).</p>",
    "14": "<p><strong>wayyōʾmer hammeleḵ lhēʿāśôṯ kēn</strong> — 'And the king commanded that it be done.' The bare command, without elaboration, signals the king's continued compliance. <strong>wattinnāṭēn dāṯ bəšûšān wayyillu ʾēṯ ʿăśeṯ bənê-Hāmān</strong> — 'an edict was given in Susa, and they hanged the ten sons of Haman.' The passive <em>wattinnāṭēn</em> (it was given) sustains the book's indirect-agency style.</p>",
    "15": "<p><strong>wayyiqqāhălû hayyəhûḏîm ʾăšer-bəšûšān gam bəyôm ʾarbāʿāh ʿāśār lə-ḥōḏeš ʾăḏār</strong> — 'The Jews who were in Susa assembled also on the fourteenth day of Adar.' The second day's battle in Susa extends the fighting one day beyond the rest of the empire. <strong>wayyahargû bəšûšān šlōšet mēʾôṯ ʾîš ûḇabizzāh lōʾ šālăḥû ʾeṯ-yāḏām</strong> — 'They killed 300 men in Susa, but they did not lay their hands on the plunder.' The refusal of plunder is repeated — the second statement in the chapter (cf. v10) — emphasizing that the no-plunder policy is consistent and intentional, not circumstantial.</p>",
    "16": "<p><strong>ûšəʾār hayyəhûḏîm ʾăšer bimdinôṯ hammeleḵ niqqahălû wəʿāmōḏ ʿal-napšām</strong> — 'The rest of the Jews who were in the king's provinces assembled and stood for their lives.' <em>Wəʿāmōḏ ʿal-napšām</em> (to stand for their lives) — the phrase from the counter-decree (8:11) is fulfilled: the Jews did precisely what they were authorized to do. <strong>wənôaḥ mēʾôyəḇêhem wəhārgû bəśōnəʾêhem ḥămiššāh wəšibʿîm ʾelep̄ ûḇabizzāh lōʾ šālăḥû ʾeṯ-yāḏām</strong> — 'and had rest from their enemies and killed 75,000 of those who hated them, but they did not lay their hands on the plunder.' <em>Nôaḥ mēʾôyəḇêhem</em> (rest from enemies, H5117 + H341) — the Deuteronomic rest formula (Deut 12:10; 25:19; Josh 21:44; 23:1) that signaled the completion of the conquest and the fulfillment of the land promise. The use of this formula here is theologically laden: the Diaspora Jews experience a form of the Deuteronomic 'rest' — relief from the threat of enemies — even outside the land.</p>",
    "17": "<p><strong>bəyôm šəlōšāh ʿāśār lə-ḥōḏeš ʾăḏār ûbəʾarbāʿāh ʿāśār bô</strong> — 'On the thirteenth day of the month of Adar and on the fourteenth day of it.' The two-day battle sequence (13th in the provinces; 13th–14th in Susa) produces the calendrical difference that will explain why different communities celebrate Purim on different dates (v18-19). <strong>wənôaḥ bəʾarbāʿāh ʿāśār bô wəʿāśôh ʾōṯô yôm mišṭeh wəśimḥāh</strong> — 'They rested on the fourteenth day and made it a day of feasting and rejoicing.' The rest-from-enemies followed by a feast-day maps onto the liturgical pattern: the Sabbath rests from labor and observes joy; here the Jews rest from battle and observe joy.</p>",
    "18": "<p><strong>wəhayyəhûḏîm ʾăšer bəšûšān niqqahălû bišlōšāh ʿāśār bô ûbəʾarbāʿāh ʿāśār bô wənôaḥ bəḥămiššāh ʿāśār bô wəʿāśôh ʾōṯô yôm mišṭeh wəśimḥāh</strong> — 'The Jews who were in Susa assembled on the thirteenth and fourteenth, and rested on the fifteenth; they made it a day of feasting and rejoicing.' The Susa Jews fought on both the 13th and 14th (the extra day Esther requested), rested on the 15th, and celebrate on the 15th. Hence two Purim dates: 14 Adar for the provincial cities (the 'open cities' or <em>ʿārê happərāzôṯ</em>, unwalled), 15 Adar for the walled cities (Susa and subsequently walled cities in Israel).</p>",
    "19": "<p><strong>ʿal-kēn hayyəhûḏîm happərāzîm hayyōšəḇîm bəʿārê happərāzôṯ ʿōśîm ʾēṯ yôm ʾarbāʿāh ʿāśār lə-ḥōḏeš ʾăḏār śimḥāh ûmišṭeh wəyôm ṭôḇ ûmišlôaḥ mānôṯ ʾîš lərēʿēhû</strong> — 'Therefore the rural Jews who live in the open villages keep the fourteenth day of the month of Adar as a day of gladness and feasting and holiday and for sending gifts of food to one another.' The term <em>happərāzîm</em> (H6521 = those who live in unwalled villages, open settlements) distinguishes the community type: no walls = 14 Adar; walled city = 15 Adar (v18). <em>Mišlôaḥ mānôṯ</em> (H4916 + H4490 = sending of portions/gifts of food) — the practice of sending portions to neighbors becomes a defining Purim practice. This reciprocal food-sharing is the social enactment of the community solidarity that made survival possible.</p>",
    "20": "<p><strong>wayyiḵtōḇ Mordoḵay ʾeṯ-hadəḇārîm hāʾēlleh wayyišlaḥ səp̄ārîm ʾel-kol-hayyəhûḏîm ʾăšer bəḵol-məḏînôṯ hammeleḵ ʾAḥašwērôš haqərôḇîm wəhārəḥôqîm</strong> — 'Mordecai recorded these things and sent letters to all the Jews in all the provinces of King Ahasuerus, both near and far.' <em>Wayyiḵtōḇ Mordoḵay ʾeṯ-hadəḇārîm hāʾēlleh</em> — 'Mordecai wrote these words' — a possible self-referential notice that Mordecai is the author/source of at least part of the Esther narrative. <em>Haqərôḇîm wəhārəḥôqîm</em> (the near and the far) is a merism covering all Jews in the Diaspora.</p>",
    "21": "<p><strong>ləqayyēm ʿălêhem lihyôṯ ʿōśîm ʾēṯ yôm ʾarbāʿāh ʿāśār lə-ḥōḏeš ʾăḏār wəʾēṯ yôm-ḥămiššāh ʿāśār bô bəḵol-šānāh wəšānāh</strong> — 'to obligate them to observe annually the fourteenth and fifteenth days of Adar.' <em>Ləqayyēm</em> (H6965, piel = to establish, confirm, ratify) — Mordecai's letters do not merely describe a past celebration but institute a perpetual obligation. <em>Bəḵol-šānāh wəšānāh</em> (in every year and year) — the distributive repetition emphasizes annual, unbroken observance across all future generations.</p>",
    "22": "<p><strong>kayyāmîm ʾăšer-nāḥû ḇāhem hayyəhûḏîm mēʾôyəḇêhem wəhaḥōḏeš ʾăšer nehpak lāhem miYyāgôn ləśimḥāh ûmēʾēḇel ləyôm ṭôḇ</strong> — 'as the days on which the Jews had rest from their enemies, and the month that had been turned for them from grief to gladness and from mourning into a holiday.' The theological summary of Purim: the month of Adar was the month Haman chose for destruction — it has been <em>nehpak</em> (H2015, niphal = turned over, reversed) from sorrow to joy. <em>MiYyāgôn ləśimḥāh ûmēʾēḇel ləyôm ṭôḇ</em> (from grief to gladness, from mourning to holiday) — paired antitheses that define the feast as the annual commemoration of reversal. <strong>laʿăśôṯ ʾôṯām yəmê mišṭeh wəśimḥāh ûmišlôaḥ mānôṯ ʾîš lərēʿēhû ûmattānôṯ lāʾeḇyônîm</strong> — 'to observe them as days of feasting and gladness, sending gifts of food to one another and gifts to the poor.' The three Purim practices: feasting, sending portions to neighbors, giving gifts to the poor (<em>ʾeḇyônîm</em>, H34).</p>",
    "23": "<p><strong>wəqibbēl hayyəhûḏîm ʾēṯ ʾăšer-hēḥēllû laʿăśôṯ wəʾēṯ ʾăšer-kāṯaḇ Mordoḵay ʾălêhem</strong> — 'So the Jews undertook to do as they had started and as Mordecai had written to them.' <em>Qibbēl</em> (H6901, piel = to receive, accept, undertake) — the community's voluntary acceptance of the feast obligation. The combination of spontaneous celebration (what they 'had started' doing) and Mordecai's written institutionalization creates the feast's dual foundation: organic commemoration and official legislation.</p>",
    "24": "<p><strong>kî Hāmān ben-Hammedāṯāʾ hāʾăgāgî ṣōrēr kol-hayyəhûḏîm ḥāšaḇ ʿal-hayyəhûḏîm ləʾabbəḏām wəhippîl pûr hûʾ-haggôrāl ləhumām ûləʾabbəḏām</strong> — 'for Haman son of Hammedatha the Agagite, the enemy of all the Jews, had planned against the Jews to destroy them and had cast Pur — that is, the lot — to crush and destroy them.' The narrative summary of chapters 3-7 is condensed into one sentence for the feast's etiological explanation. The parenthetical gloss <em>hûʾ-haggôrāl</em> (that is, the lot) explains the Akkadian loanword <em>pûr</em> (H6332) — a word that non-Hebrew speaking diaspora Jews might not recognize — and by naming the lot, the feast name Purim is explained: the feast commemorates the overthrow of the lot that Haman cast against the Jews.</p>",
    "25": "<p><strong>ûḇəḇōʾāh lip̄nê hammeleḵ ʾāmar ʿim-hassēper yāšûḇ maḥăšaḇtô hārāʿāh ʾăšer ḥāšaḇ ʿal-hayyəhûḏîm ʿal-rōʾšô</strong> — 'but when Esther came before the king, he commanded in writing that his wicked plan which he devised against the Jews should return upon his own head.' The reversal is stated in the clearest theological form: Haman's plan returned (<em>yāšûḇ</em>, H7725 = to return) upon his own head. The structure is the lex talionis in narrative form: what was plotted against others fell upon the plotter. <strong>wəṯālû ʾōṯô wəʾeṯ-bānāyw ʿal-hāʿēṣ</strong> — 'and that they should hang him and his sons on the gallows.' The hanging of Haman and his sons is the final execution of the reversal.</p>",
    "26": "<p><strong>ʿal-kēn qārəʾû layyāmîm hāʾēlleh Pûrîm ʿal-šēm happûr</strong> — 'Therefore these days were called Purim, from the word Pur.' The feast's name is explicitly derived from the Akkadian loanword: <em>pûr</em> (lot) → <em>pûrîm</em> (the plural). The feast is named after the instrument of intended destruction — a way of commemorating the instrument while celebrating its failure. This is the book's only explicit etymology. <strong>ʿal-kēn ʿal-kol-diḇrê haʾiggereṯ hazzōʾṯ</strong> — 'according to all the words of this letter.' The reference to <em>haʾiggereṯ hazzōʾṯ</em> (this letter/document) is a self-referential textual marker, indicating that the Esther scroll itself has this letter-form function.</p>",
    "27": "<p><strong>qiymû wəqibbēl hayyəhûḏîm ʿălêhem wəʿal-zaraʿām wəʿal kol-hannilvîm ʿălêhem</strong> — 'The Jews established and accepted for themselves and their descendants and all who joined them.' The tripartite community who undertakes the feast obligation: the Jews themselves, their descendants (<em>zaraʿam</em>), and the proselytes who 'joined themselves' to Israel (<em>hannilvîm</em>, H3867, niphal = those who have attached themselves, a technical term for proselytes or those who identify with Israel, cf. Isa 14:1; 56:3,6). The feast is open to those who join Israel by choice, not only those born into it. <strong>wəlōʾ yaʿăḇōr lihyôṯ ʿōśîm ʾēṯ šənê hayyāmîm hāʾēlleh ḵikəṯāḇām wəḵizzəmannām bəḵol-šānāh wəšānāh</strong> — 'that without fail they would observe these two days according to their writing and their time every year.' The double negation <em>lōʾ yaʿăḇōr</em> (will not pass over/transgress) parallels the language of unbreakable covenantal obligation.</p>",
    "28": "<p><strong>wəhayyāmîm hāʾēlleh nizkārîm wənaʿăśîm bəḵol-dôr wāḏôr bəḵol-mišpāḥāh ûmišpāḥāh bəḵol-məḏînāh ûməḏînāh ûbəḵol-ʿîr wāʿîr</strong> — 'These days should be remembered and kept throughout every generation, every clan, every province, and every city.' The four-level distribution — generation, family, province, city — exhausts all categories of human community: temporal (generations), familial (clans), political (provinces), urban (cities). <em>Nizkārîm wənaʿăśîm</em> (remembered and observed) — the two pillars of perpetual feast observance: internal memorial and external practice. <strong>wîmê hapPûrîm hāʾēlleh lōʾ yaʿăḇərû mittôḵ hayyəhûḏîm wəziḵrām lōʾ-yāsûp̄ mizzarʿām</strong> — 'these Purim days will never cease among the Jews, nor will the remembrance of them perish from their descendants.' The double assurance of perpetuity — <em>lōʾ yaʿăḇərû</em> (will not pass away) and <em>lōʾ-yāsûp̄</em> (will not end) — grounds the feast in the permanence of the events that prompted it.</p>",
    "29": "<p><strong>wattiktoḇ ʾEsṯēr hammalkāh baṯ-ʾAḇîḥayil wəMordoḵay hayyəhûḏî ʾeṯ-kol-tōqep̄ ləqayyēm ʾēṯ ʾiggereṯ hapPûrîm haззōʾṯ haššēnîṯ</strong> — 'Queen Esther daughter of Abihail and Mordecai the Jew wrote with full authority to confirm this second letter of Purim.' The joint authorship of the second Purim letter — Esther named first, then Mordecai — is significant: Esther acts not merely as Mordecai's instrument but as an authority in her own right. <em>Baṯ-ʾAḇîḥayil</em> (daughter of Abihail) — the only place in the book where Esther's father's name is given (cf. 2:15), marking this as a formal legal document that requires full identification. <em>Tōqep̄</em> (H8633 = authority, power, validity) — the legal term for the binding force of a written document.</p>",
    "30": "<p><strong>wayyišlaḥ səp̄ārîm ʾel-kol-hayyəhûḏîm ʾel šeḇaʿ wəʿeśrîm ûmēʾāh məḏînāh malkûṯ ʾAḥašwērôš diḇrê šālôm weʾěmeṯ</strong> — 'He sent letters to all the Jews in the 127 provinces of the kingdom of Ahasuerus with words of peace and truth.' <em>Diḇrê šālôm weʾěmeṯ</em> (words of peace and truth/faithfulness, H7965 + H571) — the paired attributes of the Mosaic covenant relationship (Zech 8:19) and the divine character (Exod 34:6). The phrase frames the Purim decree as aligned with covenant values: the feast celebrates not merely political survival but the continuation of the covenant community.</p>",
    "31": "<p><strong>ləqayyēm ʾēṯ-yəmê hapPûrîm hāʾēlleh biizmənêhem kaʾăšer qiyyam ʿălêhem Mordoḵay hayyəhûḏî wəʾEsṯēr hammalkāh</strong> — 'to confirm these Purim days at their proper times, as Mordecai the Jew and Queen Esther established them.' The confirmation formula repeats <em>qiyyam</em> (H6965, piel = to establish, ratify, confirm) — used three times in the Purim-establishment passage (vv27,28,31) — creating a triple ratification. <strong>wəḵaʾăšer qiyyamû ʿal-nap̄šām wəʿal-zarʿām diḇrê haṣṣômôṯ wəzaʿăqāṯām</strong> — 'and as they had established for themselves and their descendants the matters of the fastings and their lamenting.' The reference to fasting (<em>ṣômôṯ</em>, H6685) and crying out (<em>zaʿăqāṯām</em>, H2201) points back to the communal mourning of 4:3 — the fast Esther called in 4:16. The Purim feast is the inverse of the fast: the community that fasted and mourned now feasts and rejoices.</p>",
    "32": "<p><strong>ûmaʾămar ʾEsṯēr qiyyam diḇrê hapPûrîm hāʾēlleh wəniḵtaḇ bəsēfer</strong> — 'The command of Esther established these Purim practices, and it was recorded in the book.' <em>Maʾămar ʾEsṯēr</em> (Esther's command/word, H3982) — the book closes the feast-legislation with Esther's authority as its ultimate human basis. <em>Wəniḵtaḇ bəsēfer</em> (and it was written in the book) — the passive construction leaves ambiguous whether this is the book of Esther itself or the chronicles of the Persian court. The self-referential resonance is appropriate: the book of Esther is both the record of the events and the warrant for the feast.</p>"
  },
  "10": {
    "1": "<p><strong>wayyāśem hammeleḵ ʾAḥašwērôš mas ʿal-hāʾāreṣ wəʾiyyê hayyām</strong> — 'King Ahasuerus imposed tribute (<em>mas</em>, H4522 = forced labor, levy, tax) on the land and the coastlands of the sea.' The concluding chapter opens with a note of Persian imperial administration: taxation. The term <em>mas</em> designates both the practice of forced labor (as in the Solomonic levy, 1 Kgs 5:27) and tribute/taxation in kind. The 'coastlands of the sea' (<em>ʾiyyê hayyām</em>, H339 = islands, coastal regions) denotes the western territories of the empire — the Aegean coastlands of Asia Minor. The empire at maximum reach: tribute flows from its outermost territories to the Persian center.</p>",
    "2": "<p><strong>wəḵol-maʿăśēh tāqpô ûgəḇûrāṯô ûpārāšaṯ gəḏûllaṯ Mordoḵay ʾăšer giddəlô hammeleḵ hălōʾ-hēm kəṯûḇîm ʿal-sēfer diḇrê hayyāmîm ləmalkê māḏay ûp̄āras</strong> — 'All the acts of his power and strength, and the account of the greatness of Mordecai to which the king advanced him, are they not written in the book of the chronicles of the kings of Media and Persia?' The standard regnal closure formula for Israelite kings (cf. 1 Kgs 11:41; 14:19,29 etc.) is applied here to the Persian king's reign — but the closure focuses not on the king's own deeds but on <em>gəḏûllaṯ Mordoḵay</em> (Mordecai's greatness). The official royal chronicles are invoked as verification of what the Esther scroll has narrated: the story is not private legend but publicly recorded history.</p>",
    "3": "<p><strong>kî Mordoḵay hayyəhûḏî mišneh ləmeleḵ ʾAḥašwērôš wəgāḏôl layyəhûḏîm wərāṣûy lərōḇ ʾeḥāyw dōrēš ṭôḇ ləʿammô wədōḇēr šālôm ləḵol-zaraʿô</strong> — 'For Mordecai the Jew was second to King Ahasuerus, and great among the Jews, and accepted by the multitude of his brothers, seeking the welfare of his people and speaking peace to all his descendants.' The closing verse of Esther summarizes Mordecai's position in three concentric spheres: (1) the Persian court — <em>mišneh ləmeleḵ</em> (second to the king, H4932), exactly as Joseph was <em>mišneh</em> to Pharaoh (Gen 41:43); (2) the Jewish community — <em>gāḏôl layyəhûḏîm wərāṣûy lərōḇ ʾeḥāyw</em> (great among the Jews and accepted by most of his brothers; <em>rāṣāh</em>, H7521 = to find pleasure in, accept, approve); (3) his own people's future — <em>dōrēš ṭôḇ ləʿammô wədōḇēr šālôm ləḵol-zaraʿô</em> (seeking good/welfare for his people and speaking peace to all his seed). The final word is <em>zaraʿô</em> (his seed/descendants) — the book closes with the future of the Jewish people secured, not just the present crisis resolved.</p>"
  }
}

def main():
    c = load_comm('mkt-original', 'esther')
    before = sum(len(v) for v in c.values())
    merge_comm(c, EST_ORIGINAL_6_10)
    after = sum(len(v) for v in c.values())
    save_comm('mkt-original', 'esther', c)
    added = after - before
    total = sum(len(v) for v in EST_ORIGINAL_6_10.values())
    print(f'esther mkt-original ch 6-10: wrote {total} verses ({added} new)')
    # Verify
    import json as _json
    il_path = ROOT / 'data' / 'interlinear' / 'esther.json'
    if il_path.exists():
        il = _json.loads(il_path.read_text())
        for ch in ['6', '7', '8', '9', '10']:
            il_vs = set(il.get(ch, {}).keys())
            out_vs = set(c.get(ch, {}).keys())
            missing = il_vs - out_vs
            status = f'MISSING {sorted(missing, key=int)}' if missing else 'complete'
            print(f'  ch{ch}: {len(out_vs)}/{len(il_vs)} — {status}')

if __name__ == '__main__':
    main()
